//! MathML operator dictionary.
//!
//! Based on <https://www.w3.org/TR/MathML3/appendixc.html>.

use std::collections::HashMap;
use std::sync::LazyLock;

/// The form of an operator (prefix, infix, or postfix).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum OpForm {
    /// A prefix operator (e.g. unary minus, integral sign).
    Prefix,
    /// An infix operator (e.g. plus, equals).
    Infix,
    /// A postfix operator (e.g. factorial, prime).
    Postfix,
}

impl OpForm {
    /// Parse an operator form from a string.
    pub fn from_str(s: &str) -> Option<Self> {
        match s {
            "prefix" => Some(Self::Prefix),
            "infix" => Some(Self::Infix),
            "postfix" => Some(Self::Postfix),
            _ => None,
        }
    }
}

/// Attributes for a MathML operator entry.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct OpAttrs {
    /// Operator priority (higher binds tighter).
    pub priority: u16,
    /// Left space in eighteenths of an em (0..=5).
    pub lspace: u8,
    /// Right space in eighteenths of an em (0..=5).
    pub rspace: u8,
    /// Whether the operator is a fence (e.g. parenthesis, bracket).
    pub fence: bool,
    /// Whether the operator is stretchy.
    pub stretchy: bool,
    /// Whether the operator is a separator (e.g. comma).
    pub separator: bool,
    /// Whether the operator is a large operator (e.g. integral, sum).
    pub largeop: bool,
    /// Whether the operator has movable limits.
    pub movablelimits: bool,
    /// Whether the operator is an accent.
    pub accent: bool,
    /// Whether the operator is symmetric.
    pub symmetric: bool,
}

impl OpAttrs {
    const fn new(
        priority: u16,
        lspace: u8,
        rspace: u8,
        fence: bool,
        stretchy: bool,
        separator: bool,
        largeop: bool,
        movablelimits: bool,
        accent: bool,
        symmetric: bool,
    ) -> Self {
        Self {
            priority,
            lspace,
            rspace,
            fence,
            stretchy,
            separator,
            largeop,
            movablelimits,
            accent,
            symmetric,
        }
    }
}

/// Look up operator attributes by character string and form.
///
/// Returns `None` if the (character, form) pair is not in the dictionary.
pub fn op_lookup(ch: &str, form: OpForm) -> Option<&'static OpAttrs> {
    OP_DICT.get(&(ch.to_string(), form))
}

