#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_op_dict_size() {
        assert_eq!(OP_DICT.len(), 1105);
    }

    #[test]
    fn test_lookup_plus_infix() {
        let attrs = op_lookup("+", OpForm::Infix).unwrap();
        assert_eq!(attrs.priority, 275);
        assert_eq!(attrs.lspace, 4);
        assert_eq!(attrs.rspace, 4);
        assert!(!attrs.fence);
    }

    #[test]
    fn test_lookup_paren_prefix() {
        let attrs = op_lookup("(", OpForm::Prefix).unwrap();
        assert_eq!(attrs.priority, 20);
        assert!(attrs.fence);
        assert!(attrs.stretchy);
        assert!(attrs.symmetric);
    }

    #[test]
    fn test_lookup_integral_prefix() {
        let attrs = op_lookup("\u{222B}", OpForm::Prefix).unwrap();
        assert_eq!(attrs.priority, 310);
        assert!(attrs.largeop);
        assert!(attrs.symmetric);
    }

    #[test]
    fn test_lookup_missing() {
        assert!(op_lookup("xyz", OpForm::Infix).is_none());
    }
}
